// Generated by alef. Do not edit by hand — this file is the codegen for codegen.
use alef_core::backend::GeneratedFile;
use alef_core::config::{AlefConfig, resolve_output_dir};
use alef_core::ir::{ApiSurface, EnumDef, FunctionDef, PrimitiveType, TypeDef, TypeRef};
use alef_core::template_versions::cargo as tv;
use std::path::PathBuf;

/// Emit the Rust-side flutter_rust_bridge bridge crate for the given API surface.
///
/// Returns four files that together form the `packages/dart/rust/` crate:
/// - `packages/dart/rust/Cargo.toml`
/// - `packages/dart/rust/src/lib.rs`
/// - `packages/dart/rust/build.rs`
/// - `packages/dart/rust/flutter_rust_bridge.yaml`
pub fn emit(api: &ApiSurface, config: &AlefConfig) -> anyhow::Result<Vec<GeneratedFile>> {
    let rust_dir = resolve_output_dir(None, &config.crate_config.name, "packages/dart/rust");
    let module_name = dart_module_name(&config.crate_config.name);
    let source_crate_name = config.crate_config.name.replace('-', "_");

    Ok(vec![
        emit_cargo_toml(&rust_dir, config, &source_crate_name),
        emit_lib_rs(&rust_dir, api, &source_crate_name),
        emit_build_rs(&rust_dir),
        emit_frb_yaml(&rust_dir, &module_name),
    ])
}

fn emit_cargo_toml(rust_dir: &str, config: &AlefConfig, source_crate_name: &str) -> GeneratedFile {
    let crate_name = config.crate_config.name.as_str();
    let version = &api_version(config);
    let frb_version = tv::FLUTTER_RUST_BRIDGE;

    let content = format!(
        r#"[package]
name = "{crate_name}-dart"
version = "{version}"
edition = "2024"

[lib]
crate-type = ["cdylib", "staticlib"]

[dependencies]
{source_crate_name} = {{ path = "../../.." }}
flutter_rust_bridge = "{frb_version}"
"#
    );

    GeneratedFile {
        path: PathBuf::from(rust_dir).join("Cargo.toml"),
        content,
        generated_header: false,
    }
}

fn emit_lib_rs(rust_dir: &str, api: &ApiSurface, source_crate_name: &str) -> GeneratedFile {
    let mut content = String::new();
    content.push_str("// Generated by alef. Do not edit by hand.\n");
    content.push_str("use flutter_rust_bridge::frb;\n");

    for ty in &api.types {
        content.push('\n');
        emit_mirror_struct(&mut content, ty);
    }

    for en in &api.enums {
        content.push('\n');
        emit_mirror_enum(&mut content, en);
    }

    for f in &api.functions {
        content.push('\n');
        emit_bridge_fn(&mut content, f, source_crate_name);
    }

    GeneratedFile {
        path: PathBuf::from(rust_dir).join("src/lib.rs"),
        content,
        generated_header: false,
    }
}

fn emit_build_rs(rust_dir: &str) -> GeneratedFile {
    let content = "fn main() {\n    // FRB codegen runs as a separate command (`flutter_rust_bridge_codegen generate`).\n    // This build.rs is a placeholder for any pre-build steps.\n}\n".to_string();
    GeneratedFile {
        path: PathBuf::from(rust_dir).join("build.rs"),
        content,
        generated_header: false,
    }
}

fn emit_frb_yaml(rust_dir: &str, module_name: &str) -> GeneratedFile {
    let content = format!(
        "rust_input: src/lib.rs\ndart_output: ../lib/src/{module_name}_bridge_generated.dart\nrust_output: src/bridge_generated.rs\n"
    );
    GeneratedFile {
        path: PathBuf::from(rust_dir).join("flutter_rust_bridge.yaml"),
        content,
        generated_header: false,
    }
}

fn emit_mirror_struct(out: &mut String, ty: &TypeDef) {
    out.push_str(&format!("#[frb(mirror({name}))]\n", name = ty.name));
    out.push_str(&format!("pub struct _Mirror{} {{\n", ty.name));
    for field in &ty.fields {
        let rust_ty = frb_rust_type(&field.ty, field.optional);
        out.push_str(&format!("    pub {}: {rust_ty},\n", field.name));
    }
    out.push_str("}\n");
}

fn emit_mirror_enum(out: &mut String, en: &EnumDef) {
    let all_unit = en.variants.iter().all(|v| v.fields.is_empty());
    out.push_str(&format!("#[frb(mirror({name}))]\n", name = en.name));
    if all_unit {
        out.push_str(&format!("pub enum _Mirror{} {{\n", en.name));
        for variant in &en.variants {
            out.push_str(&format!("    {},\n", variant.name));
        }
        out.push_str("}\n");
    } else {
        out.push_str(&format!("pub enum _Mirror{} {{\n", en.name));
        for variant in &en.variants {
            if variant.fields.is_empty() {
                out.push_str(&format!("    {},\n", variant.name));
            } else {
                out.push_str(&format!("    {} {{\n", variant.name));
                for (idx, f) in variant.fields.iter().enumerate() {
                    let fname = if f.name.is_empty() {
                        format!("field{idx}")
                    } else {
                        f.name.clone()
                    };
                    let rust_ty = frb_rust_type(&f.ty, false);
                    out.push_str(&format!("        {fname}: {rust_ty},\n"));
                }
                out.push_str("    },\n");
            }
        }
        out.push_str("}\n");
    }
}

fn emit_bridge_fn(out: &mut String, f: &FunctionDef, source_crate_name: &str) {
    out.push_str("#[frb]\n");
    let fn_name = &f.name;
    let async_kw = if f.is_async { "async " } else { "" };

    let params: Vec<String> = f
        .params
        .iter()
        .map(|p| {
            let rust_ty = frb_rust_type(&p.ty, p.optional);
            format!("{}: {rust_ty}", p.name)
        })
        .collect();

    let call_args: Vec<String> = f.params.iter().map(|p| p.name.clone()).collect();

    let has_error = f.error_type.is_some();
    let return_ty = if has_error {
        format!("Result<{}, String>", frb_rust_return_type(&f.return_type))
    } else {
        frb_rust_return_type(&f.return_type)
    };

    out.push_str(&format!(
        "pub {async_kw}fn {fn_name}({}) -> {return_ty} {{\n",
        params.join(", ")
    ));

    let call = format!(
        "{source_crate_name}::{fn_name}({})",
        call_args.join(", ")
    );

    let body = if has_error {
        if f.is_async {
            format!("    {call}.await.map_err(|e| e.to_string())\n")
        } else {
            format!("    {call}.map_err(|e| e.to_string())\n")
        }
    } else if f.is_async {
        format!("    {call}.await\n")
    } else {
        format!("    {call}\n")
    };

    out.push_str(&body);
    out.push_str("}\n");
}

/// Maps an IR `TypeRef` to the FRB-friendly Rust type string.
/// FRB's primitive ABI: all integers → `i64`, floats → `f64`, strings → `String`.
fn frb_rust_type(ty: &TypeRef, optional: bool) -> String {
    let inner = frb_rust_type_inner(ty);
    if optional { format!("Option<{inner}>") } else { inner }
}

fn frb_rust_type_inner(ty: &TypeRef) -> String {
    match ty {
        TypeRef::Primitive(p) => match p {
            PrimitiveType::Bool => "bool".to_string(),
            PrimitiveType::F32 | PrimitiveType::F64 => "f64".to_string(),
            // All integer widths → i64 (Dart int ↔ Rust i64 FRB primitive ABI)
            _ => "i64".to_string(),
        },
        TypeRef::String | TypeRef::Char => "String".to_string(),
        TypeRef::Bytes => "Vec<u8>".to_string(),
        TypeRef::Optional(inner) => format!("Option<{}>", frb_rust_type_inner(inner)),
        TypeRef::Vec(inner) => format!("Vec<{}>", frb_rust_type_inner(inner)),
        TypeRef::Map(k, v) => {
            format!("std::collections::HashMap<{}, {}>", frb_rust_type_inner(k), frb_rust_type_inner(v))
        }
        TypeRef::Named(name) => name.clone(),
        TypeRef::Path => "String".to_string(),
        TypeRef::Unit => "()".to_string(),
        TypeRef::Json => "String".to_string(),
        TypeRef::Duration => "i64".to_string(),
    }
}

/// Return type of a bridge fn (without Result wrapper).
fn frb_rust_return_type(ty: &TypeRef) -> String {
    frb_rust_type_inner(ty)
}

fn dart_module_name(crate_name: &str) -> String {
    crate_name.replace('-', "_")
}

fn api_version(config: &AlefConfig) -> String {
    // Use explicit version override if set, otherwise fall back to "0.1.0" as a
    // safe default (the real version is resolved from Cargo.toml at publish time).
    config.version.as_deref().unwrap_or("0.1.0").to_string()
}
